<script setup lang="ts">
import type { Document as Doc } from '~/module_bindings/types'

const props = defineProps<{ doc: Doc }>()

const relativeTime = computed(() => {
  const ms = Number(props.doc.updatedAt.microsSinceUnixEpoch / 1000n)
  const diff = Date.now() - ms
  const mins = Math.floor(diff / 60000)
  if (mins < 1) return 'just now'
  if (mins < 60) return `${mins}m ago`
  const hrs = Math.floor(mins / 60)
  if (hrs < 24) return `${hrs}h ago`
  return `${Math.floor(hrs / 24)}d ago`
})

const containerRef = ref<HTMLElement | null>(null)
const previewHtml = ref<string | null>(null)
const scale = ref(0.25)

let ro: ResizeObserver | null = null

function updateScale() {
  if (containerRef.value) scale.value = containerRef.value.offsetWidth / 794
}

async function loadPreview() {
  try {
    const [
      Y,
      { IndexeddbPersistence },
      { yDocToProsemirrorJSON },
      { generateHTML },
      { default: StarterKit },
      { TextStyle },
      { default: Color },
      { default: FontFamily },
      { default: TextAlign },
      { default: Underline },
      { default: Highlight },
      { default: Link },
      { default: Superscript },
      { default: Subscript },
      { default: Image },
      { default: TaskList },
      { default: TaskItem },
      { Table },
      { TableRow },
      { TableHeader },
      { TableCell },
      { CommentMark },
      { InsertionMark, DeletionMark },
    ] = await Promise.all([
      import('yjs'),
      import('y-indexeddb'),
      import('@tiptap/y-tiptap'),
      import('@tiptap/core'),
      import('@tiptap/starter-kit'),
      import('@tiptap/extension-text-style'),
      import('@tiptap/extension-color'),
      import('@tiptap/extension-font-family'),
      import('@tiptap/extension-text-align'),
      import('@tiptap/extension-underline'),
      import('@tiptap/extension-highlight'),
      import('@tiptap/extension-link'),
      import('@tiptap/extension-superscript'),
      import('@tiptap/extension-subscript'),
      import('@tiptap/extension-image'),
      import('@tiptap/extension-task-list'),
      import('@tiptap/extension-task-item'),
      import('@tiptap/extension-table'),
      import('@tiptap/extension-table-row'),
      import('@tiptap/extension-table-header'),
      import('@tiptap/extension-table-cell'),
      import('~/components/editor/extensions/CommentMark'),
      import('~/components/editor/extensions/TrackChanges'),
    ])

    const ydoc = new Y.Doc()
    const persistence = new IndexeddbPersistence(`documint-${props.doc.id}`, ydoc)
    await persistence.whenSynced

    const json = yDocToProsemirrorJSON(ydoc, 'default')
    previewHtml.value = generateHTML(json as any, [
      StarterKit,
      TextStyle,
      Color,
      FontFamily.configure({ types: ['textStyle'] }),
      TextAlign.configure({ types: ['heading', 'paragraph'] }),
      Underline,
      Highlight.configure({ multicolor: true }),
      Link.configure({ openOnClick: false, HTMLAttributes: { class: 'doc-link' } }),
      Superscript,
      Subscript,
      Image,
      TaskList,
      TaskItem.configure({ nested: true }),
      Table,
      TableRow,
      TableHeader,
      TableCell,
      CommentMark,
      InsertionMark,
      DeletionMark,
    ])

    persistence.destroy()
    ydoc.destroy()
  } catch {
    previewHtml.value = ''
  }
}

onMounted(() => {
  nextTick(() => {
    if (containerRef.value) {
      ro = new ResizeObserver(updateScale)
      ro.observe(containerRef.value)
      updateScale()
    }
    loadPreview()
  })
})

onBeforeUnmount(() => {
  ro?.disconnect()
})
</script>

<template>
  <NuxtLink
    :to="`/doc/${doc.id}`"
    class="group flex flex-col overflow-hidden rounded-xl border border-gray-200 shadow-sm transition-all hover:border-mint-500/60 hover:shadow-md dark:border-gray-700 dark:hover:border-mint-500/40"
  >
    <!-- A4 portrait preview -->
    <div ref="containerRef" class="relative overflow-hidden bg-white" style="aspect-ratio: 1 / 1.4142">
      <div
        class="pointer-events-none absolute left-0 top-0 origin-top-left select-none"
        :style="{ width: '794px', transform: `scale(${scale})` }"
      >
        <div v-if="previewHtml" class="doc-content doc-card-preview-content" v-html="previewHtml" />
        <div v-else class="doc-card-preview-skeleton">
          <div v-if="doc.title" class="doc-card-preview-skeleton-title">{{ doc.title }}</div>
          <div class="doc-card-preview-skeleton-lines">
            <div /><div style="width:78%" /><div /><div style="width:62%" />
            <div /><div style="width:88%" /><div /><div style="width:71%" />
          </div>
        </div>
      </div>
    </div>
    <!-- Footer -->
    <div class="flex flex-col gap-0.5 border-t border-gray-100 bg-white px-3 py-2.5 dark:border-gray-800 dark:bg-gray-900">
      <span class="line-clamp-1 text-sm font-medium text-gray-900 dark:text-white">{{ doc.title || 'Untitled' }}</span>
      <span class="text-xs text-gray-400">{{ relativeTime }}</span>
    </div>
  </NuxtLink>
</template>
